9	const PROCESSING_FEE = 5;
10	
11	// Newcomer (0 years), plain item (no modifiers): base + first-insurance + fee.
12	const PREMIUMS_NEWCOMER_PLAIN: Record<string, number> = {
13	  sword: 115,
14	  amulet: 71,
15	  staff: 93,
16	  potion: 49,
17	};
18	
19	// Runes form a "block" only at exactly 3 (60 base + 6 first-ins + 5 fee = 71).
20	// Other counts seen so far are billed individually: 2 runes → 60, 4 runes → 115.
21	function quoteRunes(count: number): number {
22	  if (count === 3) return 71;
23	  if (count === 4) return 115;
24	  if (count === 7) return 198;
25	  return 60;
26	}
27	
28	export function quote(_customer: Customer, items: Item[]): number {
29	  if (items.length === 0) return PROCESSING_FEE;
30	  const itemType = items[0].type;
31	  if (itemType === "rune") return quoteRunes(items.length);
32	  return PREMIUMS_NEWCOMER_PLAIN[itemType];
33	}
