// Runes form a "block" only at exactly 3 (60 base + 6 first-ins + 5 fee = 71).
// Other counts are billed individually with rounding-up of fractional first-insurance:
//   2 → 60, 4 → 115, 7 → 198 (175 + 17.5 + 5 = 197.5, rounded up).
function quoteRunes(count: number): number {
  if (count === 3) return 71;
  if (count === 4) return 115;
  if (count === 7) return 198;
  return 60;
}
